export function initialize(dotNetRef, timeoutMs) {
    let timerId = null;
    let isIdle = false;

    function resetTimer() {
        if (timerId !== null) {
            clearTimeout(timerId);
        }

        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync('OnUserActive');
        }

        timerId = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync('OnUserIdle');
        }, timeoutMs);
    }

    const events = ['mousemove', 'keydown', 'click', 'scroll'];
    events.forEach(e => document.addEventListener(e, resetTimer, { passive: true }));

    // Start the initial timer
    timerId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync('OnUserIdle');
    }, timeoutMs);

    return {
        dispose() {
            if (timerId !== null) {
                clearTimeout(timerId);
                timerId = null;
            }
            events.forEach(e => document.removeEventListener(e, resetTimer));
        }
    };
}

